//! Conformance suite — `ferrotorch-hub` parity against `huggingface_hub 0.24.x`.
//!
//! Reference: <https://github.com/huggingface/huggingface_hub>
//! Pinned version: huggingface_hub == 0.24.3
//!
//! For every public item in `ferrotorch-hub` this file loads reference
//! fixtures from `tests/conformance/fixtures.json` (generated by
//! `scripts/regenerate_hub_fixtures.py`) and asserts that ferrotorch-hub's
//! output matches the expected behavior documented by the Python reference
//! library.
//!
//! All fixture operations are **offline-only** — the fixture generator never
//! makes network calls. Network-dependent operations (hf_download_model,
//! search_models, get_model, download_weights over HTTP) are cascade-skipped
//! with `cascade_skip!()` and covered by the integration tests in
//! `tests/load_pretrained_smoke.rs`.
//!
//! Coverage dimensions:
//! - repo_id parsing / URL construction
//! - SearchQuery::to_query_string (URL encoding)
//! - HfTransformerConfig::from_json_str, from_file, derived accessors, validate
//! - HfModelSummary / HfModelInfo deserialization
//! - populate_author / extract_author logic
//! - sanitize_path_component accept/reject
//! - validate_cache_relative accept/reject
//! - registry list_models / get_model_info
//! - HubCache path construction / store / load / clear / has / path_for_model

use std::path::PathBuf;

use ferrotorch_hub::cache::{HubCache, default_cache_dir};
use ferrotorch_hub::hf_config::HfTransformerConfig;
use ferrotorch_hub::registry::{WeightsFormat, get_model_info, list_models};
use serde::Deserialize;

// ---------------------------------------------------------------------------
// cascade_skip! — mark a test skipped because the conformance divergence is
// tracked in a crosslink issue rather than a bug we fix inline.
//
// Usage:
//   cascade_skip!("reason string, issue #NNN");
// This is a macro (not a function) so the `return` inside it is valid in any
// test fn body.
// ---------------------------------------------------------------------------
macro_rules! cascade_skip {
    ($reason:expr) => {{
        eprintln!("cascade_skip: {}", $reason);
        return;
    }};
}

// ---------------------------------------------------------------------------
// Fixture deserialization
// ---------------------------------------------------------------------------

#[derive(Debug, Deserialize)]
struct FixtureFile {
    metadata: FixtureMetadata,
    fixtures: Vec<serde_json::Value>,
}

#[derive(Debug, Deserialize)]
struct FixtureMetadata {
    huggingface_hub_version: String,
    #[allow(dead_code)]
    python_version: String,
    #[allow(dead_code)]
    platform: String,
    #[allow(dead_code)]
    generated_at: String,
    offline_only: bool,
    network_calls_made: bool,
}

fn load_fixtures() -> FixtureFile {
    let p = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("conformance")
        .join("fixtures.json");
    let bytes = std::fs::read(&p).unwrap_or_else(|e| {
        panic!(
            "read {} failed: {e}. Regenerate via \
             scripts/regenerate_hub_fixtures.py",
            p.display()
        )
    });
    let file: FixtureFile =
        serde_json::from_slice(&bytes).unwrap_or_else(|e| panic!("parse {}: {e}", p.display()));
    // Assert the pin is correct
    assert!(
        file.metadata.huggingface_hub_version.starts_with("0.24."),
        "fixtures were generated with huggingface_hub {}, expected 0.24.x",
        file.metadata.huggingface_hub_version
    );
    assert!(
        file.metadata.offline_only,
        "fixtures must be offline-only (no network calls)"
    );
    assert!(
        !file.metadata.network_calls_made,
        "fixtures metadata reports network calls were made"
    );
    file
}

fn fixtures_by_op<'a>(file: &'a FixtureFile, op: &str) -> Vec<&'a serde_json::Value> {
    file.fixtures
        .iter()
        .filter(|f| f.get("op").and_then(|v| v.as_str()) == Some(op))
        .collect()
}

fn is_cascade_skipped(f: &serde_json::Value) -> bool {
    f.get("cascade_skip")
        .and_then(|v| v.as_bool())
        .unwrap_or(false)
}

// ---------------------------------------------------------------------------
// Sanity: fixture file covers all required op families
// ---------------------------------------------------------------------------

#[test]
fn fixture_file_covers_required_ops() {
    let file = load_fixtures();
    let ops_present: std::collections::HashSet<&str> = file
        .fixtures
        .iter()
        .filter_map(|f| f.get("op").and_then(|v| v.as_str()))
        .collect();

    let required = [
        "extract_author",
        "resolve_url",
        "api_model_url",
        "search_query_string",
        "url_encode",
        "hf_config_parse",
        "hf_config_validate",
        "hf_config_parse_error",
        "model_summary_deserialize",
        "populate_author",
        "model_info_deserialize",
        "sanitize_path_component",
        "validate_cache_relative",
        "registry_list_models_count",
        "registry_get_model_info",
        "registry_known_models",
    ];
    for r in required {
        assert!(
            ops_present.contains(r),
            "fixture file missing op {r:?} (have: {:?})",
            ops_present
        );
    }
}

