#[test]
fn extract_author_matches_reference() {
    let file = load_fixtures();
    let cases = fixtures_by_op(&file, "extract_author");
    assert!(!cases.is_empty(), "no extract_author fixtures");

    for f in cases {
        let repo_id = f["repo_id"].as_str().unwrap();
        let expected_author: Option<&str> = f["expected_author"].as_str();

        // The Rust impl splits on '/' and takes the first segment.
        let actual: Option<String> = repo_id.split_once('/').map(|(ns, _)| ns.to_string());
        let label = format!("extract_author repo_id={repo_id:?}");

        assert_eq!(
            actual.as_deref(),
            expected_author,
            "{label}: actual={actual:?} expected={expected_author:?}"
        );
    }
}

