#[test]
fn registry_list_models_count_matches_reference() {
    let file = load_fixtures();
    let cases = fixtures_by_op(&file, "registry_list_models_count");
    assert!(!cases.is_empty(), "no registry_list_models_count fixtures");

    let models = list_models();
    for f in cases {
        let expected_count = f["expected_count"].as_u64().unwrap() as usize;
        assert_eq!(
            models.len(),
            expected_count,
            "registry list_models count mismatch: actual={} expected={}",
            models.len(),
            expected_count
        );
    }
}

#[test]
fn registry_get_model_info_matches_reference() {
    let file = load_fixtures();
    let cases = fixtures_by_op(&file, "registry_get_model_info");
    assert!(!cases.is_empty(), "no registry_get_model_info fixtures");

    for f in cases {
        let name = f["name"].as_str().unwrap();
        let expected_some = f["expected_some"].as_bool().unwrap();

        let info = get_model_info(name);
        assert_eq!(
            info.is_some(),
            expected_some,
            "get_model_info({name:?}): expected_some={expected_some}, got={:?}",
            info.map(|i| i.name)
        );

        if expected_some {
            let info = info.unwrap();
            let expected_params =
                f["expected_num_parameters"].as_u64().unwrap() as usize;
            assert_eq!(
                info.num_parameters, expected_params,
                "get_model_info({name:?}): num_parameters mismatch"
            );
            let expected_fmt = f["expected_format"].as_str().unwrap();
            let actual_fmt = match info.format {
                WeightsFormat::SafeTensors => "SafeTensors",
                WeightsFormat::FerrotorchStateDict => "FerrotorchStateDict",
            };
            assert_eq!(
                actual_fmt, expected_fmt,
                "get_model_info({name:?}): format mismatch"
            );
        }
    }
}

